  // Calculate the position of the next iteration
  nx = x + dx * 0.5;
  ny = y - dy * 0.8660254037844386;

  // Draw a smaller heart at the next position
  drawHeartFractal(nx, ny, dx * 0.5, dy * 0.8660254037844386, depth - 1);
}

